// Learn: Use a record with validation and ordering.
import java.util.Locale;

record Badge(String email, int level) implements Comparable<Badge> {
  public Badge {
    // Compact constructors can normalize record components.
    email = email.strip().toLowerCase(Locale.ROOT);
    if (level < 1) throw new IllegalArgumentException("level");
  }

  boolean senior() {
    return level >= 5;
  }

  public int compareTo(Badge other) {
    return email.compareTo(other.email());
  }
}

Badge badge = new Badge(" ADMIN@Example.COM ", 5);
System.out.println(badge.email());
